import socket
import threading
import math

class GameServer:
    def __init__(self, host='127.0.0.1', port=12345):
        self.host = host
        self.port = port
        self.clients = []
        self.game_state = {
            'players': {},
            'map': {}
        }

    def broadcast(self, message):
        for client in self.clients:
            client.send(message)

    def handle_client(self, client):
        while True:
            try:
                data = client.recv(1024)
                if not data:
                    break
                # Handle client commands (e.g. movement, shooting)
                command = data.decode('utf-8')
                if command.startswith('move'):
                    player_id = command.split(':')[0]
                    position = command.split(':')[1].split(',')
                    self.game_state['players'][player_id] = {
                        'position': [float(position[0]), float(position[1])],
                        'velocity': [0, 0]
                    }
                elif command.startswith('shoot'):
                    player_id = command.split(':')[0]
                    target_id = command.split(':')[1]
                    self.game_state['players'][player_id]['shooting'] = True
                    self.game_state['players'][target_id]['health'] -= 10
            except Exception as e:
                print(f'Error handling client: {e}')
                break
        self.clients.remove(client)
        client.close()

    def send_game_state(self, client):
        game_state_str = str(self.game_state).encode('utf-8')
        client.send(game_state_str)

    def run(self):
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.bind((self.host, self.port))
        server_socket.listen(5)
        print(f'Server listening on {self.host}:{self.port}')

        while True:
            client_socket, address = server_socket.accept()
            self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

            # Send initial game state to new client
            self.send_game_state(client_socket)

            # Broadcast player positions to all clients
            for player_id, player in self.game_state['players'].items():
                position_str = f'{player_id}:{player["position"][0]},{player["position"][1]}'
                self.broadcast(position_str.encode('utf-8'))

if __name__ == '__main__':
    game_server = GameServer()
    game_server.run()